import React, { useEffect, useRef } from 'react';

const CanvasBackground = () => {
  const canvasRef = useRef(null);

  useEffect(() => {
    const c = canvasRef.current;
    const $ = c.getContext('2d');

    const col = function(x, y, r, g, b) {
      $.fillStyle = "rgb(" + (r-100) + "," + (g-100) + "," + (b-100) + ")";
      $.fillRect(x, y, 1,1);
    }
    const R = function(x, y, t) {
      return( Math.floor(128 + 64*Math.cos( (x*x-y*y)/300 + t )) );
    }

    const G = function(x, y, t) {
      return( Math.floor(128 + 64*Math.sin( (x*x*Math.cos(t/4)+y*y*Math.sin(t/3))/300 ) ) );
    }

    const B = function(x, y, t) {
      return( Math.floor(128 + 64*Math.sin( 5*Math.sin(t/9) + ((x-100)*(x-100)+(y-100)*(y-100))/1100) ));
    }
    let t = 0;

    const run = () => {
      const { width, height } = c.getBoundingClientRect();
      c.width = width;
      c.height = height;

      for(let x=0;x<=35;x++) {
        for(let y=0;y<=35;y++) {
          col(x, y, R(x,y,t), G(x,y,t), B(x,y,t));
        }
      }
      t = t + 0.005;
      window.requestAnimationFrame(run);
    }

    run();
  }, []);

  return <canvas ref={canvasRef} style={{ position: 'fixed', top: 0, left: 0, zIndex: -1, width: '100vw', height: '100vh' }} />;
};

export default CanvasBackground;
